package sampling

// Noisy operation configuration used by the instrumentation config.
// It is similar to the NoisyOperation struct, but includes a rule id and excludes irrelevant fields.
// The original struct cannot be used as the id property is internal and should not appear in user-facing API.
// +kubebuilder:object:generate=true
type NoisyOperation struct {

	// The id of the rule (auto-generated by the system)
	Id string `json:"id"`

	// The name of the rule (user-provided) used for display, reference, sampling-metrics attricute and span attributes enhancments.
	Name string `json:"name,omitempty"`

	// If set to true, the rule will not be taken into account for any sampling decisions, but still participate in metrics calculations.
	Disabled bool `json:"disabled,omitempty"`

	// The operation to match for sampling.
	Operation *HeadSamplingOperationMatcher `json:"operation,omitempty"`

	// The percentage of spans to sample for this rule.
	// traces will be sampled "at most" this percentage
	// (meaning, we can sample less than this percentage if other rules requires more aggressive sampling).
	PercentageAtMost *float64 `json:"percentageAtMost,omitempty"`
}

// Highly relevant operation configuration used by the instrumentation config.
// It is similar to the HighlyRelevantOperation struct, but includes a rule id and excludes irrelevant fields.
// The original struct cannot be used as the id property is internal and should not appear in user-facing API.
// +kubebuilder:object:generate=true
type HighlyRelevantOperation struct {
	// The id of the rule (auto-generated by the system)
	Id string `json:"id"`

	// The name of the rule (user-provided) used for display, reference, sampling metrics and span attributes enhancements.
	Name string `json:"name,omitempty"`

	// If set to true, the rule will not be taken into account for any sampling decisions, but still participate in metrics calculations.
	Disabled bool `json:"disabled,omitempty"`

	// If set to true, only spans with SpanStatus set to Error are considered.
	Error bool `json:"error,omitempty"`

	// If set, only operations with duration in milliseconds larger than this value are considered.
	DurationAtLeastMs *int `json:"durationAtLeastMs,omitempty"`

	// The operation to match for sampling.
	Operation *TailSamplingOperationMatcher `json:"operation,omitempty"`

	// Traces that contain this operation will be sampled by at least this percentage.
	PercentageAtLeast *float64 `json:"percentageAtLeast,omitempty"`
}

// Cost reduction rule configuration used by the instrumentation config.
// It is similar to the CostReductionRule struct, but includes a rule id and excludes irrelevant fields.
// The original struct cannot be used as the id property is internal and should not appear in user-facing API.
// +kubebuilder:object:generate=true
type CostReductionRule struct {
	// The id of the rule (auto-generated by the system)
	Id string `json:"id"`

	// The name of the rule (user-provided) used for display, reference, sampling metrics and span attributes enhancements.
	Name string `json:"name,omitempty"`

	// If set to true, the rule will not be taken into account for any sampling decisions, but still participate in metrics calculations.
	Disabled bool `json:"disabled,omitempty"`

	// The operation to match for sampling.
	Operation *TailSamplingOperationMatcher `json:"operation,omitempty"`

	// Sampling percentage for cost reduction; traces matching this rule will be sampled at most this percentage.
	PercentageAtMost float64 `json:"percentageAtMost"`
}

// +kubebuilder:object:generate=true
type TailSamplingSourceConfig struct {

	// Specify any operations you consider as noisy or disruptive to the observability of the trace.
	// These operations will be ignored from tracing regardless of any error, latency rules, or special conditions rule.
	NoisyOperations []NoisyOperation `json:"noisyOperations,omitempty"`

	// Specify any operations you consider as highly relevant to the observability of the trace.
	// These operations will be kept regardless of any cost reduction rules.
	HighlyRelevantOperations []HighlyRelevantOperation `json:"highlyRelevantOperations,omitempty"`

	// Specify any operations you consider as cost reduction rules.
	// These operations will be aggresively sampled out to reduce the cost of tracing.
	CostReductionRules []CostReductionRule `json:"costReductionRules,omitempty"`
}
